const raw = $input.item.json;
const aiText = raw.output[0].content[0].text;
const aiData = JSON.parse(aiText.replace(/```json|```/g, '').trim());

const contexto = $('Preparar Contexto').item.json;
const forceInternal = contexto.force_internal === true;
const is2500 = contexto.is_2500 === true;
const numeroAvisos = contexto.numero_avisos || 1;
const clientCode = String(contexto.client_center_code || '');

let targetType = aiData.decision?.target_type || 'standard';
if (forceInternal || is2500) targetType = 'internal';

const shouldNotify = aiData.decision?.should_notify === true;

const emailTo = targetType === 'internal'
  ? 'alertas@sergi.com'
  : (clientCode.match(/^454160000[1-2]$/) ? 'cca.z2@cttexpress.com' : 'cca.z3@cttexpress.com');

return {
  should_notify: shouldNotify,
  target_type: targetType,
  email_subject: shouldNotify ? (aiData.decision?.email_subject || '') : '',
  email_body: shouldNotify ? (aiData.decision?.email_body || '') : '',
  ai_incident_detected: aiData.analysis?.detected_incident || 'N/A',
  ai_justification: aiData.analysis?.justification || 'Sin detalle',
  h_en_estado: aiData.analysis?.hours_in_status || 0,
  email_to: emailTo,
  numero_avisos: numeroAvisos,
  force_internal: forceInternal,
  is_2500: is2500
};

