parameters.jsCode:
const rows = $input.all();
const item = $('Code in JavaScript3').item.json;
const hoy = $now.toFormat('dd-MM-yyyy');
const ayer = $now.minus({days: 1}).toFormat('dd-MM-yyyy');

const filasValidas = rows.filter(r => r.json['NUMERO DE ENVIO']);

const filasHoy = filasValidas.filter(r => {
  const fecha = (r.json['FECHA PROCESADO'] || '').substring(0, 10);
  return fecha === hoy;
});

const filasAyer = filasValidas.filter(r => {
  const fecha = (r.json['FECHA PROCESADO'] || '').substring(0, 10);
  return fecha === ayer;
});

const is2500 = String(item.shipping_status_code || '') === '2500';

const skip = filasHoy.length > 0;
const forceInternal = !skip && (filasAyer.length > 0 || is2500);
const numeroAvisos = filasValidas.length + 1;

return {
  json: {
    ...item,
    skip,
    force_internal: forceInternal,
    is_2500: is2500,
    numero_avisos: numeroAvisos
  }
};

try {
  const item = $('Loop: Processar 1 a 2').first().json;
  const history = $input.item.json;
  let events = [];

  if (history?.data?.shipping_history?.events) {
    events = history.data.shipping_history.events;
  } else if (Array.isArray(history)) {
    const data = history[0];
    if (data?.data?.shipping_history?.events) {
      events = data.data.shipping_history.events;
    }
  }

  const has1600 = events.some(e => e.code === '1600' || e.event_code === '1600');

  // ─── PARSEO Y FORMATO DEL HISTORIAL ─────────────────────────────────────────
  let parsedEvents = []; // { date: Date, code: string }
  let formattedHistory = 'Sin eventos disponibles';

  if (events.length > 0) {
    formattedHistory = events.map(e => {
      let date = e.event_date || e.item_event_date || '';
      let parsedDate = null;

      if (date) {
        try {
          const d = new Date(date);
          d.setHours(d.getHours() + 1); // UTC+1 Madrid
          parsedDate = d;
          date = d.toISOString().replace('T', ' ').substring(0, 16);
        } catch (x) {}
      }

      const code = e.code || e.event_code || 'N/A';
      const desc = e.description || e.event_description || '';
      const detail = e.detail?.External_event_text || e.detail?.item_event_text || '';

      if (parsedDate) {
        parsedEvents.push({ date: parsedDate, code });
      }

      return `${date} - [${code}] ${desc} (${detail})`;
    }).join('\n');
  }

  // ─── CÁLCULO DE HORAS LABORABLES ────────────────────────────────────────────
  // Lunes=1 ... Viernes=5, Sábado=6, Domingo=0
  function businessHours(startDate, endDate) {
    if (!startDate || !endDate || endDate <= startDate) return 0;
    let hours = 0;
    let cur = new Date(startDate.getTime());

    while (cur < endDate) {
      const dow = cur.getDay(); // 0=Dom, 6=Sab
      if (dow !== 0 && dow !== 6) {
        const y = cur.getFullYear(), m = cur.getMonth(), d = cur.getDate();
        const nextMidnight = new Date(y, m, d + 1);
        const seg = endDate < nextMidnight ? endDate : nextMidnight;
        hours += (seg - cur) / 3600000;
      }
      const y = cur.getFullYear(), m = cur.getMonth(), d = cur.getDate();
      cur = new Date(y, m, d + 1);
    }

    return parseFloat(hours.toFixed(1));
  }

  const now = new Date();

  const TRANSIT    = ['0900', '1000'];
  const DELIVERY   = ['1200', '1500'];
  const STATIONARY = ['1700', '1800'];
  const MANIFEST   = ['0000', '0030'];

  // TRÁNSITO: desde el primer 0900/1000, solo si no hay 1200/1500 posterior
  const firstTransit = parsedEvents.find(e => TRANSIT.includes(e.code));
  let transitHours = 0;
  if (firstTransit) {
    const hasDeliveryAfter = parsedEvents.some(
      e => DELIVERY.includes(e.code) && e.date > firstTransit.date
    );
    if (!hasDeliveryAfter) {
      transitHours = businessHours(firstTransit.date, now);
    }
  }

  // MANIFESTADO: desde primer 0000/0030, solo si aún no hay tránsito ni reparto
  const firstManifest = parsedEvents.find(e => MANIFEST.includes(e.code));
  let manifestHours = 0;
  if (firstManifest && !firstTransit) {
    manifestHours = businessHours(firstManifest.date, now);
  }

  // CICLO REPARTO: reset en cada 1000 después de 1200/1500
  // Regla: el ciclo empieza en el primer 1200/1500 del ciclo actual
  // Cada 1000 posterior a un 1200/1500 reinicia el ciclo
  let deliveryCycleStart = null;
  let inDelivery = false;
  for (const event of parsedEvents) {
    if (DELIVERY.includes(event.code)) {
      if (!inDelivery) {
        deliveryCycleStart = event.date;
        inDelivery = true;
      }
    } else if (event.code === '1000' && inDelivery) {
      deliveryCycleStart = null;
      inDelivery = false;
    }
  }
  let deliveryHours = 0;
  if (deliveryCycleStart) {
    deliveryHours = businessHours(deliveryCycleStart, now);
  }

  // ESTACIONADO: desde el último 1700/1800
  const lastStationary = [...parsedEvents].reverse().find(e => STATIONARY.includes(e.code));
  let stationaryHours = 0;
  if (lastStationary) {
    stationaryHours = businessHours(lastStationary.date, now);
  }

  // ─── OUTPUT ─────────────────────────────────────────────────────────────────
  return {
    json: {
      ...item,
      status_history: events,
      formatted_history: formattedHistory,
      history_has_1600: has1600,
      total_events: events.length,
      // Horas precalculadas para la IA
      transit_hours:    transitHours,
      manifest_hours:   manifestHours,
      delivery_hours:   deliveryHours,
      stationary_hours: stationaryHours
    }
  };

} catch (error) {
  throw new Error(`[Code JS3] ${error.message}`);
}

